import pytest

def partial(fn, *partial_args, **partial_kwargs):
    def wrapper(*args, **kwargs):
        merged = {**partial_kwargs, **kwargs}
        return fn(*partial_args, *args, **merged)
    return wrapper

def add(x, y, z=0):
    return x + y + z

def multiply(x, y, z=1):
    return x * y * z

def divide(x, y):
    if y == 0:
        raise ZeroDivisionError("Cannot divide by zero")
    return x / y

