    assert add_5(3) == 8
    assert add_5(3, z=2) == 10

def test_partial_add_multiple_partial_args():
    add_5_and_3 = partial(add, 5, 3)
    assert add_5_and_3() == 8
    assert add_5_and_3(z=2) == 10

def test_partial_add_partial_kwargs():
